Rule.Source:
  import sailpoint.object.Identity;
  import sailpoint.object.Link;
  import sailpoint.tools.Util;

  private boolean hasAzureLink(Identity identity) {

    boolean hasAzureLink = false;
    List azureLinks = getIdentityAppLinks(identity, "Azure"); //Sourced from Ascension-RuleLibrary-GSuite

    if (azureLinks != null && !azureLinks.isEmpty()) {

      hasAzureLink = true;

    }

    return hasAzureLink;

  }

  boolean hasAzureLink = false;
  boolean inactive = true;
  String orgUnitPath = null;

  if (identity != null) {

    hasAzureLink = hasAzureLink(identity);
    inactive = identity.isInactive();
    orgUnitPath = identity.getAttribute("orgUnitPath");
    List validOUs = Util.csvToList("/EMP/Mobile, /CWR/Mobile");
    
    //Check if Identity has Azure, is active, and has one of two specific orgUnitPath values

    if (hasAzureLink && !inactive && Util.nullSafeContains(validOUs, orgUnitPath)) {

      return true;

    }

  }

  return false;
